pointMarker.code:
type PointMarkerVariant = "default" | "muted" | "completed" | "emphasized";

async function renderPointMarker(map: google.maps.Map, position: google.maps.LatLngLiteral, variant: PointMarkerVariant) {
  const { AdvancedMarkerElement } = await google.maps.importLibrary("marker");
  const content = document.createElement("div");
  content.className = `MapMarker MapMarker--advanced MapMarker--point-${variant}`;

  return new AdvancedMarkerElement({
    anchorLeft: "-50%",
    anchorTop: "-50%",
    content,
    map,
    position,
  });
}

informatedLocation.code:
type InformatedLocationVariant = "default" | "disabled" | "completed" | "emphasized";

async function renderInformatedLocation(map: google.maps.Map, position: google.maps.LatLngLiteral, variant: InformatedLocationVariant) {
  const { AdvancedMarkerElement } = await google.maps.importLibrary("marker");
  const visualVariant = variant === "disabled" ? "muted" : variant;
  const content = document.createElement("div");
  content.className = `MapMarker MapMarker--advanced MapMarker--informated-${visualVariant}`;

  return new AdvancedMarkerElement({
    content,
    map,
    position,
  });
}

cumulativeLocation.code:
interface ClusterNode {
  count: number;
  position: google.maps.LatLngLiteral;
  children?: ClusterNode[];
}

function renderByZoom(node: ClusterNode, zoom: number) {
  if (zoom >= 7 && !node.children?.length) {
    return <NormalPoint position={node.position} />;
  }

  if (zoom >= 5 && node.children?.length) {
    return node.children.map((child) => renderByZoom(child, zoom));
  }

  return <CumulativeLocation count={node.count} position={node.position} />;
}

const example = {
  count: 42,
  children: [
    { count: 10, children: [{ count: 3 }, { count: 7 }] },
    { count: 32, children: [{ count: 12 }, { count: 20 }] },
  ],
};

