type CustomLocationContent = "letter" | "number" | "warehouse" | "shop" | "user";

async function renderCustomLocation(map: google.maps.Map, position: google.maps.LatLngLiteral, contentType: CustomLocationContent) {
  const { AdvancedMarkerElement } = await google.maps.importLibrary("marker");
  const content = document.createElement("div");
  content.className = "MapMarker MapMarker--advanced MapMarker--custom-default";
  content.dataset.content = contentType;

  return new AdvancedMarkerElement({
    anchorLeft: "-50%",
    anchorTop: "-50%",
    content,
    map,
    position,
  });
}

